final class csmMoc extends ffi.Opaque {}

final class csmModel extends ffi.Opaque {}

/// 2 component vector.
final class csmVector2 extends ffi.Struct {
  /// First component.
  @ffi.Float()
  external double X;

  /// Second component.
  @ffi.Float()
  external double Y;
}

/// 4 component vector.
final class csmVector4 extends ffi.Struct {
  /// 1st component.
  @ffi.Float()
  external double X;

  /// 2nd component.
  @ffi.Float()
  external double Y;

  /// 3rd component.
  @ffi.Float()
  external double Z;

  /// 4th component.
  @ffi.Float()
  external double W;
}

/// Cubism version identifier.
typedef csmVersion = ffi.UnsignedInt;
typedef DartcsmVersion = int;

/// moc3 version identifier.
typedef csmMocVersion = ffi.UnsignedInt;
