/// Log handler.
///
/// @param  message  Null-terminated string message to log.
typedef csmLogFunction =
    ffi.Pointer<ffi.NativeFunction<csmLogFunctionFunction>>;
typedef csmLogFunctionFunction =
    ffi.Void Function(ffi.Pointer<ffi.Char> message);
typedef DartcsmLogFunctionFunction =
    void Function(ffi.Pointer<ffi.Char> message);

/// Parameter type.
typedef csmParameterType = ffi.Int;
typedef DartcsmParameterType = int;

/// Bitfield.
typedef csmFlags = ffi.UnsignedChar;
typedef DartcsmFlags = int;

